export default function urbansThreadsIcons({
  name,
  size = 48,
  className = "",
}: IconProps) {
  const icon = icons[name];
  if (!icon) return null;

  return (
    <div style={{ width: size, height: size }} className={className}>
      {icon}
    </div>
  );
}

